import{_ as p,C as d,o as r,c as l,a5 as o,b as s,w as a,a as n,E as i,a6 as c}from"./chunks/framework.XBmRGoM0.js";const f=JSON.parse('{"title":"Control planes and workspaces","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/control-planes.md","filePath":"concepts/control-planes.md"}'),h={name:"concepts/control-planes.md"};function u(m,e,A,k,P,b){const t=d("Mermaid");return r(),l("div",null,[e[2]||(e[2]=o('<h1 id="control-planes-and-workspaces" tabindex="-1">Control planes and workspaces <a class="header-anchor" href="#control-planes-and-workspaces" aria-label="Permalink to &quot;Control planes and workspaces&quot;">​</a></h1><p>Platform Mesh uses kcp as its control-plane substrate. kcp provides the Kubernetes-compatible API layer, workspace isolation, and API sharing primitives that Platform Mesh builds on for accounts, providers, consumers, and marketplace-style service consumption.</p><p>This page explains the Platform Mesh usage model. It intentionally does not replace the upstream kcp documentation for kcp-owned behavior.</p><h2 id="why-kcp-is-the-substrate" tabindex="-1">Why kcp is the substrate <a class="header-anchor" href="#why-kcp-is-the-substrate" aria-label="Permalink to &quot;Why kcp is the substrate&quot;">​</a></h2><p>Platform Mesh needs a shared control plane where service providers can publish declarative APIs and service consumers can use those APIs without getting direct access to provider runtimes.</p><p>kcp fits that role because it keeps the Kubernetes Resource Model as the common API shape while separating it from Kubernetes cluster scheduling. In Platform Mesh terms, kcp acts as the API orchestration layer: it gives providers and consumers a Kubernetes-style API surface for service management instead of a container orchestration surface.</p><p>That means existing Kubernetes clients and controller patterns still apply, but the resources describe service requests, bindings, account state, and provider integrations rather than pods on a workload cluster.</p><h2 id="workspaces-in-platform-mesh" tabindex="-1">Workspaces in Platform Mesh <a class="header-anchor" href="#workspaces-in-platform-mesh" aria-label="Permalink to &quot;Workspaces in Platform Mesh&quot;">​</a></h2><p>Platform Mesh uses kcp workspaces to provide isolated Kubernetes-compatible API surfaces for accounts, providers, consumers, and marketplace-related flows.</p><p>The important Platform Mesh idea is:</p><ul><li>account boundaries map to control-plane boundaries</li><li>provider APIs are published from provider spaces</li><li>consumer accounts bind provider APIs into their own workspaces</li><li>Platform Mesh components reconcile across those spaces while preserving authorization boundaries</li></ul><p>The Account is the Platform Mesh abstraction. The workspace is the kcp mechanism that gives the account its isolated API surface and authorization boundary.</p><h2 id="workspace-hierarchy" tabindex="-1">Workspace hierarchy <a class="header-anchor" href="#workspace-hierarchy" aria-label="Permalink to &quot;Workspace hierarchy&quot;">​</a></h2><p>Workspaces are hierarchical. Platform Mesh uses that hierarchy to represent organizational and account structure while keeping API resources isolated at each level.</p>',14)),(r(),s(c,null,{default:a(()=>[i(t,{id:"mermaid-61",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20Root%5B%22root%22%5D%0A%20%20%20%20Root%20--%3E%20Providers%5B%22providers%22%5D%0A%20%20%20%20Root%20--%3E%20OrgA%5B%22org-a%22%5D%0A%20%20%20%20Root%20--%3E%20OrgB%5B%22org-b%22%5D%0A%0A%20%20%20%20Providers%20--%3E%20HttpBinProvider%5B%22httpbin-provider%22%5D%0A%20%20%20%20Providers%20--%3E%20MongoProvider%5B%22mongodb-provider%22%5D%0A%0A%20%20%20%20OrgA%20--%3E%20TeamA%5B%22team-a%22%5D%0A%20%20%20%20OrgA%20--%3E%20TeamB%5B%22team-b%22%5D%0A%0A%20%20%20%20OrgB%20--%3E%20TeamC%5B%22team-a%22%5D%0A%20%20%20%20OrgB%20--%3E%20TeamD%5B%22team-b%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=o('<p>A workspace has a path, such as <code>:root:org-a:team-a</code>. This avoids name conflicts between branches and gives platform owners a way to map organizational structure into the control plane.</p><p>kcp workspace types allow defining which APIs are available by default and which parts of the hierarchy are allowed in a given area. Platform Mesh uses that to separate provider spaces, consumer account spaces, and marketplace or registry spaces without making every workspace identical.</p><h2 id="provider-and-consumer-workspaces" tabindex="-1">Provider and consumer workspaces <a class="header-anchor" href="#provider-and-consumer-workspaces" aria-label="Permalink to &quot;Provider and consumer workspaces&quot;">​</a></h2><p>Provider integration is based on the <code>APIExport</code> and <code>APIBinding</code> pattern:</p><ul><li>a provider publishes a service API from a provider workspace with an <code>APIExport</code></li><li>a consumer binds that exported API into its own workspace with an <code>APIBinding</code></li><li>the consumer creates desired-state resources in its own workspace</li><li>the provider reconciles those resources and reports status back through the control plane</li></ul>',5)),(r(),s(c,null,{default:a(()=>[i(t,{id:"mermaid-96",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20Provider%5B%22Provider%20workspace%22%5D%0A%20%20%20%20%20%20%20%20Schema%5B%22APIResourceSchema%22%5D%0A%20%20%20%20%20%20%20%20Export%5B%22APIExport%22%5D%0A%20%20%20%20%20%20%20%20Schema%20--%3E%20Export%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20ConsumerA%5B%22Consumer%20workspace%20A%22%5D%0A%20%20%20%20%20%20%20%20BindingA%5B%22APIBinding%22%5D%0A%20%20%20%20%20%20%20%20ResourceA%5B%22Service%20resource%22%5D%0A%20%20%20%20%20%20%20%20BindingA%20--%3E%20ResourceA%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20ConsumerB%5B%22Consumer%20workspace%20B%22%5D%0A%20%20%20%20%20%20%20%20BindingB%5B%22APIBinding%22%5D%0A%20%20%20%20%20%20%20%20ResourceB%5B%22Service%20resource%22%5D%0A%20%20%20%20%20%20%20%20BindingB%20--%3E%20ResourceB%0A%20%20%20%20end%0A%0A%20%20%20%20BindingA%20-.%20binds%20.-%3E%20Export%0A%20%20%20%20BindingB%20-.%20binds%20.-%3E%20Export%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[n(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<p>This is the main control-plane relationship between providers and consumers. APIExports and APIBindings connect the workspaces, while the account model decides who owns each workspace and who is allowed to use it.</p><p>Provider controllers do not need full access to every consumer workspace. kcp exposes APIExport virtual workspaces that let a provider watch and reconcile the resources created from the APIs it provides. Access remains limited to the exported API surface and is guarded by authorization checks.</p><h2 id="marketplace-and-composition" tabindex="-1">Marketplace and composition <a class="header-anchor" href="#marketplace-and-composition" aria-label="Permalink to &quot;Marketplace and composition&quot;">​</a></h2><p>The same export and binding model enables a marketplace-like flow. Consumers can discover APIs they are allowed to see, bind the ones they want to use, and then manage provider services through declarative resources in their own workspace.</p><p>The API schema is the contract between provider and consumer. This keeps provider implementation details behind the API boundary while still giving consumers a consistent way to request, update, and observe service instances.</p><p>Because the shared interface follows the Kubernetes Resource Model, consumers and providers can also compose services across provider boundaries. For example, one provider can write credentials or connection details as Kubernetes-style resources, and another provider can consume them through a separate API contract.</p><h2 id="platform-mesh-mapping" tabindex="-1">Platform Mesh mapping <a class="header-anchor" href="#platform-mesh-mapping" aria-label="Permalink to &quot;Platform Mesh mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform Mesh concept</th><th>kcp mechanism</th><th>Purpose</th></tr></thead><tbody><tr><td>Account</td><td>Workspace</td><td>Gives an organization, team, provider, or consumer an isolated API surface.</td></tr><tr><td>Provider API</td><td>APIResourceSchema and APIExport</td><td>Publishes the schema and API surface a provider offers.</td></tr><tr><td>Consumer subscription</td><td>APIBinding</td><td>Makes a provider API available in a consumer workspace.</td></tr><tr><td>Provider reconciliation</td><td>APIExport virtual workspace</td><td>Lets provider automation observe and reconcile consumer-created resources for its exported API.</td></tr></tbody></table><h2 id="what-to-learn-from-upstream-kcp" tabindex="-1">What to learn from upstream kcp <a class="header-anchor" href="#what-to-learn-from-upstream-kcp" aria-label="Permalink to &quot;What to learn from upstream kcp&quot;">​</a></h2><p>kcp owns the full semantics of workspaces, workspace types, virtual workspaces, APIExports, APIBindings, APIResourceSchemas, permission claims, and sharding behavior.</p><p>Use these upstream docs for canonical behavior:</p><ul><li><a href="https://docs.kcp.io/kcp/main/concepts/workspaces/" target="_blank" rel="noreferrer">kcp workspaces</a></li><li><a href="https://docs.kcp.io/kcp/main/concepts/apis/exporting-apis/" target="_blank" rel="noreferrer">kcp exporting and binding APIs</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./account-model.html">Account model</a></li><li><a href="./api-sharing.html">API sharing</a></li><li><a href="./integration-paths.html">Integration paths</a></li></ul>',14))])}const w=p(h,[["render",u]]);export{f as __pageData,w as default};
